152: // The key of these side-table hash maps are intentionally not traced GC
153: // references to JSScript. Instead, we use bare pointers and manually fix up
154: // when objects could have moved (see Zone::fixupScriptMapsAfterMovingGC) and
155: // remove when the realm is destroyed (see Zone::clearScriptCounts and
156: // Zone::clearScriptNames). They essentially behave as weak references, except
157: // that the references are not cleared early by the GC. They must be non-strong
158: // references because the tables are kept at the Zone level and otherwise the
159: // table keys would keep scripts alive, thus keeping Realms alive, beyond their
160: // expected lifetimes. However, We do not use actual weak references (e.g. as
161: // used by WeakMap tables provided in gc/WeakMap.h) because they would be
162: // collected before the calls to the JSScript::finalize function which are used
163: // to aggregate code coverage results on the realm.
164: //
165: // Note carefully, however, that there is an exceptional case for which we *do*
166: // want the JSScripts to be strong references (and thus traced): when the
167: // --dump-bytecode command line option or the PCCount JSFriend API is used,
168: // then the scripts for all counts must remain alive. See
169: // Zone::traceScriptTableRoots() for more details.
170: //
171: // TODO: Clean this up by either aggregating coverage results in some other
172: // way, or by tweaking sweep ordering.
173: using UniqueScriptCounts = js::UniquePtr<ScriptCounts>;
174: using ScriptCountsMap =
175:     GCRekeyableHashMap<HeapPtr<BaseScript*>, UniqueScriptCounts,
176:                        DefaultHasher<HeapPtr<BaseScript*>>, SystemAllocPolicy>;
177: 
178: // The 'const char*' for the function name is a pointer within the LCovSource's
179: // LifoAlloc and will be discarded at the same time.
180: using ScriptLCovEntry = std::tuple<coverage::LCovSource*, const char*>;
181: using ScriptLCovMap =
182:     GCRekeyableHashMap<HeapPtr<BaseScript*>, ScriptLCovEntry,
183:                        DefaultHasher<HeapPtr<BaseScript*>>, SystemAllocPolicy>;
