951:  private:
952:   /*
953:    * Gets the next token and checks if it matches to the given `condition`.
954:    * If it matches, returns true.
955:    * If it doesn't match, calls `errorReport` to report the error, and
956:    * returns false.
957:    * If other error happens, it returns false but `errorReport` may not be
958:    * called and other error will be thrown in that case.
959:    *
960:    * In any case, the already gotten token is not ungotten.
961:    *
962:    * The signature of `condition` is [...](TokenKind actual) -> bool, and
963:    * the signature of `errorReport` is [...](TokenKind actual).
964:    */
965:   template <typename ConditionT, typename ErrorReportT>
966:   [[nodiscard]] bool mustMatchTokenInternal(ConditionT condition,
967:                                             ErrorReportT errorReport);
968: 
969:  public:
970:   /*
971:    * The following mustMatchToken variants follow the behavior and parameter
972:    * types of mustMatchTokenInternal above.
973:    *
974:    * If modifier is omitted, `SlashIsDiv` is used.
975:    * If TokenKind is passed instead of `condition`, it checks if the next
976:    * token is the passed token.
977:    * If error number is passed instead of `errorReport`, it reports an
978:    * error with the passed errorNumber.
979:    */
980:   [[nodiscard]] bool mustMatchToken(TokenKind expected, JSErrNum errorNumber) {
981:     return mustMatchTokenInternal(
982:         [expected](TokenKind actual) { return actual == expected; },
983:         [this, errorNumber](TokenKind) { this->error(errorNumber); });
984:   }
985: 
986:   template <typename ConditionT>
987:   [[nodiscard]] bool mustMatchToken(ConditionT condition,
988:                                     JSErrNum errorNumber) {
989:     return mustMatchTokenInternal(condition, [this, errorNumber](TokenKind) {
990:       this->error(errorNumber);
991:     });
992:   }
993: 
994:   template <typename ErrorReportT>
995:   [[nodiscard]] bool mustMatchToken(TokenKind expected,
996:                                     ErrorReportT errorReport) {
997:     return mustMatchTokenInternal(
998:         [expected](TokenKind actual) { return actual == expected; },
999:         errorReport);
1000:   }
