2354: bool BytecodeEmitter::emitScript(ParseNode* body) {
2355:   setScriptStartOffsetIfUnset(body->pn_pos.begin);
2356: 
2357:   MOZ_ASSERT(inPrologue());
2358: 
2359:   TDZCheckCache tdzCache(this);
2360:   EmitterScope emitterScope(this);
2361:   Maybe<AsyncEmitter> topLevelAwait;
2362:   if (sc->isGlobalContext()) {
2363:     if (!emitterScope.enterGlobal(this, sc->asGlobalContext())) {
2364:       return false;
2365:     }
2366:   } else if (sc->isEvalContext()) {
2367:     if (!emitterScope.enterEval(this, sc->asEvalContext())) {
2368:       return false;
2369:     }
2370:   } else {
2371:     MOZ_ASSERT(sc->isModuleContext());
2372:     if (!emitterScope.enterModule(this, sc->asModuleContext())) {
2373:       return false;
2374:     }
2375:     if (sc->asModuleContext()->isAsync()) {
2376:       topLevelAwait.emplace(this);
2377:     }
2378:   }
2379: 
2380:   setFunctionBodyEndPos(body->pn_pos.end);
2381: 
2382:   bool isSloppyEval = sc->isEvalContext() && !sc->strict();
2383:   if (isSloppyEval && body->is<LexicalScopeNode>() &&
2384:       !body->as<LexicalScopeNode>().isEmptyScope()) {
2385:     // Sloppy eval scripts may emit hoisted functions bindings with a
2386:     // `JSOp::GlobalOrEvalDeclInstantiation` opcode below. If this eval needs a
2387:     // top-level lexical environment, we must ensure that environment is created
2388:     // before those functions are created and bound.
2389:     //
2390:     // This differs from the global-script case below because the global-lexical
2391:     // environment exists outside the script itself. In the case of strict eval
2392:     // scripts, the `emitterScope` above is already sufficient.
2393:     EmitterScope lexicalEmitterScope(this);
2394:     LexicalScopeNode* scope = &body->as<LexicalScopeNode>();
2395: 
2396:     if (!lexicalEmitterScope.enterLexical(this, ScopeKind::Lexical,
2397:                                           scope->scopeBindings())) {
2398:       return false;
2399:     }
2400: 
2401:     if (!emitDeclarationInstantiation(scope->scopeBody())) {
2402:       return false;
2403:     }
2404: 
2405:     switchToMain();
2406: 
2407:     ParseNode* scopeBody = scope->scopeBody();
2408:     if (!emitLexicalScopeBody(scopeBody)) {
2409:       return false;
2410:     }
2411: 
2412:     if (!updateSourceCoordNotes(scopeBody->pn_pos.end)) {
2413:       return false;
2414:     }
2415: 
2416:     if (!lexicalEmitterScope.leave(this)) {
2417:       return false;
2418:     }
2419:   } else {
2420:     if (!emitDeclarationInstantiation(body)) {
2421:       return false;
2422:     }
2423:     if (topLevelAwait) {
2424:       if (!topLevelAwait->prepareForModule()) {
2425:         return false;
2426:       }
2427:     }
2428: 
2429:     switchToMain();
2430: 
2431: #ifdef ENABLE_EXPLICIT_RESOURCE_MANAGEMENT
2432:     if (!emitterScope.prepareForModuleDisposableScopeBody(this)) {
2433:       return false;
2434:     }
2435: #endif
2436: 
2437:     if (topLevelAwait) {
2438:       if (!topLevelAwait->prepareForBody()) {
2439:         return false;
2440:       }
2441:     }
2442: 
